sql:
SELECT COUNT(report_id) AS total_damage_reports
FROM damage_reports
WHERE year = 2023;

external_knowledge:
- "storm of financial ruin" metaphorically refers to significant financial losses due to damage incidents;
- "sweep through most forcefully" indicates the highest financial impact or total loss;
- The query is designed to identify states experiencing the greatest financial losses due to approved damage reports.

sql:
SELECT state_id, COUNT(*) AS total_reports
FROM damage_reports
GROUP BY state_id;

SELECT report_id, acres, loss, report_date
FROM damage_reports
WHERE year = 2001;

SELECT report_id, year, loss AS total_loss
FROM damage_reports
ORDER BY year DESC;

SELECT SUM(loss_per_acre) AS total_loss_per_acre
FROM damage_reports
WHERE year = 2001;

SELECT total_acres
FROM monthly_summary
WHERE year = 2023 AND month = 'JAN';

SELECT SUM(d.loss) AS total_loss
FROM damage_reports d
WHERE d.year = 2022;
